async (params, browser) => {
  // Open competitions search
  await browser.open(`https://www.kaggle.com/competitions?search=${params.query}`)

  // Wait for competition results
  await browser.waitForSelector('a[href*=\'/competitions/\']', 15000)

  // Let results render
  await browser.wait(3000)

  // Scroll for more results
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract competitions
  const results = await browser.evaluate(`const results = []; const seen = new Set(); document.querySelectorAll('a[href*="/competitions/"]').forEach(a => { const href = a.getAttribute('href') || ''; if (!href.match(/^\/competitions\/[^/]+$/) || seen.has(href)) return; seen.add(href); const title = a.textContent.trim(); if (!title || title.length > 200 || title.length < 3) return; const parent = a.closest('li') || a.closest('div[class]') || a.parentElement; const allText = parent ? parent.textContent : ''; const prizeMatch = allText.match(/\$[\d,]+/); const teamMatch = allText.match(/(\d[\d,]*)\s*teams?/i); const spans = parent ? Array.from(parent.querySelectorAll('span, p')).map(e => e.textContent.trim()).filter(t => t.length > 5 && t !== title) : []; results.push({ title: title.substring(0, 200), url: 'https://www.kaggle.com' + href, prize: prizeMatch ? prizeMatch[0] : '', teams: teamMatch ? teamMatch[1] : '', metadata: spans.slice(0, 3).join(' | ') }); }); return { query: '' + params.query + '', result_count: results.length, results: results.slice(0, 15) };`)

  return results
}
